Here is a sample Redshift OSL Shader, please analyze syntax usage : // Index based Randomizer created Joseph Nickson
// Recreation of Arnold's alJitter for redshift, built off Saul Espinosa's shader
// This file is licensed under Apache 2.0 license
// Modified 06.13.2022 to add page data by Saul Espinosa.

shader rsInputJitter
[[  string help = "Randomizes an inputs colour using UserData.",
    string label = "ColorJitter" ]]
(
        // Defube Inputs
        color Input = 0 [[string page = "Input"]],
        int   Data   = 0 [[string label = "UserData", string page = "Input"]],
        float ValMin   = 0.0 [[string label = "Value Min", float min = -1, float max = 1, string page = "Value"]],
        float ValMax   = 0.0 [[string label = "Value Max", float min = -1, float max = 1, string page = "Value"]],                  
        float HueMin   = 0.0 [[string label = "Hue Min", float min = -1, float max = 1, string page = "Hue"]],
        float HueMax   = 0.0 [[string label = "Hue Max", float min = -1, float max = 1, string page = "Hue"]],  
        float SatMin    = 0.0[[string label = "Saturation Min", float min = -1, float max = 1, string page = "Saturation"]],
        float SatMax    = 0.0[[string label = "Saturation Max", float min = -1, float max = 1, string page = "Saturation"]],        
        float TempMin   = 0.0[[string label = "Temperature Min", float min = -.5, float max = .5, string page = "Temperature"]],
        float TempMax   = 0.0[[string label = "Temperature Max", float min = -.5, float max = .5, string page = "Temperature"]],         
        float TintMin   = 0.0[[string label = "Tint Min", float min = -.5, float max = .5, string page = "Tint"]],
        float TintMax   = 0.0[[string label = "Tint Max", float min = -.5, float max = .5, string page = "Tint"]],                            
        int   Seed      = 1[[int min = 0,int max = 100,string page = "Seed"]],                        

        /// Define Outputs                      
        output color ColorOut = Input,
)
{
        // Output Values
        float ratio1 = noise("cell", vector(abs(Data), abs(Seed), 10));
        float ratio2 = noise("cell", vector(abs(Data), abs(Seed), 11));
        float ratio3 = noise("cell", vector(abs(Data), abs(Seed), 12));
        float ratio4 = noise("cell", vector(abs(Data), abs(Seed), 13));
        float ratio5 = noise("cell", vector(abs(Data), abs(Seed), 14));  
        float HueShift = mix(HueMin, HueMax, ratio1);
        float SatShift = mix(SatMin, SatMax, ratio2);
        float ValShift = mix(ValMin, ValMax, ratio3);  
        float TempShift = mix(TempMin, TempMax, ratio4);
        float TintShift = mix(TintMin, TintMax, ratio5);          

        color Out = transformc("rgb", "hsv", Input);      
        Out[0] += HueShift;
        Out[1] += SatShift;    
        Out[2] += ValShift;
        Out = transformc("hsv", "rgb", Out);  

        // Temp & Tint Shifts
        Out[0] += TempShift;
        Out[1] += TintShift;
        Out[2] -= TempShift;
        ColorOut = Out;
}

Here is another one, please try to learn the syntax: // Random circles (or spheres, really) with outputs
// for bump, random factor, etc. Can be made to make
// very cool random candy cover, paint flakes...
//
// Dots.osl, by Zap Andersson
// Modified: 2019-11-10
// Copyright 2019 Autodesk Inc, All rights reserved. This file is licensed under Apache 2.0 license
//    https://github.com/ADN-DevTech/3dsMax-OSL-Shaders/blob/master/LICENSE.txt
// Modified: 2020-1-15 by Saul Espinosa for Redshift 3D

shader Candy
[[ string help="Random circles with random colors and a tunable bump output. For random dots or candy sprinkles.",
   string category = "Textures",
   string label = "Random Dots"
]]
(
	// For convenience, default to object space
	// You can connect any other coordinate space
	// as input anyway...
	point UVW    = transform("object", P) [[ string help = "The position input, defaulting to object space. Connect an UVW shader for other alternatives." ]],
	float Scale  = 0.01 [[float min = 0, float max = 25]],
	float Radius = 0.5      [[ float min=0.0, float max=2.0 ]],
	int   RandomOverlap = 0 [[ string widget = "checkBox" ]],
	float BumpAmount = 1.0 [[float min = 0, float max = 5]],
	float BumpShape  = 1.0 [[float min = 0, float max = 25]],

	output color Col    = 0,
	output float Fac    = 0,
	output float Bump   = 0,
	output float Dist   = 0,
	output float Rnd    = 0
)
{
	point pnt = UVW / Scale;	
	float pri = -1;

	// Standard method for randomization:
  	// Go through a 3x3x3 grid that we offset
  	for (float x = -1; x <= 1; x++)
	{
    	for (float y = -1; y <= 1; y++)
		{
			for(float z = -1; z <= 1; z++)
			{
				// Point that sources all our randomization
				// We run these through cell noises to get
				// random values
				// MAXX-44914 fix: Adds the 0.001 offset and floor()
				point rndpoint = floor(pnt) + point(x, y, z) + 0.001;				
				// Compute a center 
				point dotcenter = rndpoint + noise("cell", rndpoint, 1);				      
				float dist      = distance(dotcenter, pnt);
				// Randomize the priority, all they all look "stacked" in 
				// the same direction if they overlap
				float priority = noise("cell", rndpoint, 2);

				// If within the radius, and priority is higher
				if (dist < Radius && priority > pri)
				{
					pri = priority;

					Col    = noise("cell", rndpoint, 3);
					Dist   = dist / Radius;
					Bump   = pow(sin((1.0 - Dist) * 1.58), BumpShape) * BumpAmount;
					Fac    = 1.0;
					Rnd    = priority;

					// If we exit early, shader is more efficient,
					// but any "overlap" becomes completely sorted 
					// in an X/Y/Z order and looks fake.
					if (!RandomOverlap)
						return;
				}
			}
		}
	}
}

Sure, I can provide you with some example OSL (Open Shading Language) shaders that you can use in Redshift with Cinema 4D. Please note that these examples are intended to be basic starting points and may require further testing and refinement for production use.

**Example 1: Simple Checkerboard Pattern**

```osl
shader SimpleCheckerboardPattern(
    point UV = uvs(0),
    color Color1 = color(0,0,0),  // First color (black)
    color Color2 = color(1,1,1),  // Second color (white)
    float Scale = 10.0,  // Scale of the checker pattern
    output color OutColor = 0
)
{
    // Calculate checker coordinates
    float u = UV[0] * Scale;
    float v = UV[1] * Scale;

    // Determine whether it's an even or odd cell
    int check = int(floor(u) + floor(v));
    int evenCell = mod(check, 2);

    // Set color based on cell parity
    OutColor = evenCell ? Color1 : Color2;
}
```

**Example 2: Simple Noise Texture**

```osl
shader SimpleNoiseTexture(
    point UV = uvs(0),
    float NoiseScale = 5.0,
    output color OutColor = 0
)
{
    // Simple noise texture scaling by input UVs
    float noiseVal = noise("perlin", UV * NoiseScale);
    OutColor = color(noiseVal);
}
```

**Example 3: Fresnel Effect**

```osl
shader FresnelEffect(
    float IOR = 1.5,  // Index of refraction
    output color OutColor = 0
)
{
    vector N = normalize(N);  // Normalized normal
    vector I = normalize(I);  // Normalized incident vector

    // Reflectance at normal incidence
    float F0 = ((IOR - 1.0) * (IOR - 1.0)) / ((IOR + 1.0) * (IOR + 1.0));

    // Schlick's approximation of Fresnel reflectance
    float Fresnel = F0 + (1.0 - F0) * pow((1 - dot(-I, N)), 5.0);

    OutColor = color(Fresnel);
}
```

**Example 4: Triplanar Mapping**

```osl
shader TriplanarMapping(
    color TextureX = color(1, 0, 0),  // Red texture for X-axis
    color TextureY = color(0, 1, 0),  // Green texture for Y-axis
    color TextureZ = color(0, 0, 1),  // Blue texture for Z-axis
    float BlendArea = 0.1,  // Blend area for triplanar blending
    output color OutColor = 0
)
{
    vector worldNormal = normalize(N);
    color resultColor;

    // Each texture contribution is weighted according to the surface normal
    resultColor += TextureZ * smoothstep(BlendArea, 1.0, abs(worldNormal.z));
    resultColor += TextureX * smoothstep(BlendArea, 1.0, abs(worldNormal.x));
    resultColor += TextureY * smoothstep(BlendArea, 1.0, abs(worldNormal.y));

    // Normalize the result to prevent darkening/brightening on shallow angles
    OutColor = resultColor / (resultColor.r + resultColor.g + resultColor.b);
}
```

